                <h3 className="text-xl font-bold mb-4 flex items-center gap-2 text-teal-800"><Stethoscope /> Consultar Guías EAU 2025</h3>
                <div className="flex gap-4">
                    <input type="text" value={eauQuery} onChange={e => setEauQuery(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleEAUSearch()} placeholder="Ej. Recomendación para CaP Gleason 7 post-op..." className="flex-1 p-4 border border-slate-300 rounded-xl" />
                    <button onClick={handleEAUSearch} disabled={eauLoading} className="bg-teal-600 text-white px-8 rounded-xl font-bold">{eauLoading ? <Loader2 className="animate-spin" /> : 'Consultar'}</button>
                </div>
                {eauResult && (
                    <div className="mt-6 p-6 bg-slate-50 rounded-2xl border border-slate-200 prose prose-slate max-w-none">
                        <ReactMarkdown>{eauResult}</ReactMarkdown>
                    </div>
                )}
            </div>
        </div>
      )}

      {activeTab === 'tools' && (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 animate-slide-up">
            {aiTools.map(tool => (
                <div key={tool.name} className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                    <div className="flex justify-between mb-3"><span className="text-[10px] font-bold px-2 py-0.5 rounded bg-teal-50 text-teal-700 border border-teal-200">AI Tool</span><span className="text-[10px] font-bold text-slate-400">{tool.category}</span></div>
                    <h4 className="font-bold text-slate-900 mb-2">{tool.name}</h4>
                    <p className="text-sm text-slate-600 mb-4">{tool.description}</p>
                    <a href={tool.url} target="_blank" className="w-full py-2 bg-slate-900 text-white rounded-xl text-xs font-bold flex items-center justify-center gap-2 hover:bg-slate-800 transition-colors"><ExternalLink size={12}/> Abrir Herramienta</a>
                </div>
            ))}
        </div>
      )}
    </div>
  );
};

export default ResearchHub;
